INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('29-people-os',3,29,'PEOPLE OS','He dieu hanh nhan su',29,'draft','2026-06-20T16:30:10Z','2026-06-20T16:30:10Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cd04939d-a1ac-4ffe-b783-dfc2b6e21714','29-people-os',NULL,2,'29.1 People OS - Hệ Thống Quản Trị Và Giải Phóng Hiệu Suất Đội Ngũ','291-people-os-he-thong-quan-tri-va-giai-phong-hieu-suat-oi-ngu',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef0c0bb4-e2b0-4d11-a845-1759d105765d','cd04939d-a1ac-4ffe-b783-dfc2b6e21714',0,'text','Nếu **Finance OS** cung cấp cho phòng khám một hệ thống luật chơi sòng phẳng và tấm bản đồ dòng tiền minh bạch, thì **People OS** chính là bộ máy chuyển hóa những mục tiêu tài chính trên giấy thành hiện thực đầu ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ef653c8-fba8-4fe7-ab91-362f1d4f4dac','cd04939d-a1ac-4ffe-b783-dfc2b6e21714',1,'text','Suy cho cùng, các con số trên Dashboard tài chính không tự nhiên nhảy múa. Hệ thống CRM không tự vận hành, kênh TikTok không tự sản xuất nội dung sạch, và bệnh nhân không tự nhiên có được trải nghiệm "Wow". Tất cả những mắt xích đó đều được vận hành bởi một yếu tố duy nhất: **Con người**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0459f2ec-4859-47f8-8cc1-bbd28a47ac01','29-people-os','cd04939d-a1ac-4ffe-b783-dfc2b6e21714',3,'Sự Chuyển Dịch Mô Hình: Từ Phụ Thuộc Cá Nhân Sang Sức Mạnh Đội Ngũ','su-chuyen-dich-mo-hinh-tu-phu-thuoc-ca-nhan-sang-suc-manh-oi-ngu',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10bab370-30f4-49eb-808d-dbd1c117b0af','0459f2ec-4859-47f8-8cc1-bbd28a47ac01',2,'text','Một phòng khám nha khoa muốn bứt phá quy mô không thể mãi vận hành theo mô hình "một ngôi sao và những người làm công". Nếu mọi ca đại phẫu Implant, mọi quyết định tư vấn phác đồ lớn hay ngay cả việc nhắc lịch hẹn đều phải đi qua bộ não của Bác sĩ ngôi sao, phòng khám đó thực chất chỉ là một cơ sở kinh doanh hộ cá thể quy mô nhỏ nơi người chủ đang tự làm thuê cho chính mình với mức lương cao.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f17bf603-64cb-4269-952e-28bb5b787239','0459f2ec-4859-47f8-8cc1-bbd28a47ac01',3,'text','**People OS** được thiết lập để đập tan giới hạn tăng trưởng tuyến tính đó, dịch chuyển toàn diện cấu trúc nhân sự của nha khoa qua hai trạng thái vận hành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('868c1ff7-f97d-490f-b925-6bcb8713829e','0459f2ec-4859-47f8-8cc1-bbd28a47ac01',4,'image',NULL,'book/29-people-os/7d6b36bb-6574-4280-ae77-a4b642711af7-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('870398c0-23f3-40e0-b2e9-776165493b7b','29-people-os','cd04939d-a1ac-4ffe-b783-dfc2b6e21714',3,'Bốn Trụ Cột Bảo Chứng Hiệu Suất Của People OS','bon-tru-cot-bao-chung-hieu-suat-cua-people-os',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b45c553a-7656-4223-b4eb-ecdaa8766da1','870398c0-23f3-40e0-b2e9-776165493b7b',5,'text','Bước vào phân hệ **People OS,** chúng ta sẽ lần lượt thiết lập 4 tầng kiến trúc để xây dựng một đội ngũ tự chủ, tinh nhuệ và đồng nhất về mặt văn hóa y khoa tử tế:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ecaecb54-90b2-44ae-88e9-8732b8908053','870398c0-23f3-40e0-b2e9-776165493b7b',6,'text','- **Sơ đồ tổ chức & Định biên nhân sự (Org Chart):** Phân rã rõ ràng quyền hạn, trách nhiệm và tuyến báo cáo của từng vị trí từ Lễ tân sảnh, Phụ tá lâm sàng, Chuyên viên TCO cho đến các Bác sĩ hợp tác.- **Khung năng lực tiêu chuẩn (Competency Framework):** Định nghĩa tường minh thế nào là một nhân sự đạt chuẩn tại sàn đầu ghế nha, triệt tiêu tình trạng đánh giá cảm tính.- **Hệ thống đãi ngộ và giải phóng động lực (Compensation & Gamification):** Thiết kế cơ chế lương thưởng bậc thang thông minh, gắn chặt hiệu suất làm việc với dòng tiền thực thu của Finance OS để nhân sự tự chủ động gia tăng năng suất.- **Văn hóa thực thi và kỷ luật (Operational Culture):** Xây dựng các bộ Checklist hằng ngày, quy trình bàn giao ca nghiêm ngặt để đảm bảo chất lượng dịch vụ đồng đều 100% trên mọi lượt khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('41eb5181-32a2-466a-9cc7-a3362efd9922','870398c0-23f3-40e0-b2e9-776165493b7b',7,'image',NULL,'book/29-people-os/2b8c2fc8-f6c9-4d84-80ce-1b4710cbcbd9-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d07b4b11-8cf2-4aad-a270-8d6be02af234','870398c0-23f3-40e0-b2e9-776165493b7b',8,'text','**Mantra chuyển giao hệ thống:***"Finance OS giúp chúng ta kiểm soát hơi thở của doanh nghiệp, nhưng chính People OS mới là thực thể tạo ra sự sống. Hãy ngừng tìm kiếm những ''ngôi sao'' cô độc để vá víu bộ máy, hãy tập trung xây dựng một hệ thống quản trị con người khoa học để biến những nhân sự bình thường thành một đội ngũ vận hành phi thường."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1d0e6877-3178-4f7a-8ac5-c06f77abde13','29-people-os','cd04939d-a1ac-4ffe-b783-dfc2b6e21714',3,'Tư Duy Quản Trị: Thoát Khỏi Cái Bẫy "Khổ Chủ" Trong Kinh Doanh Nha Khoa','tu-duy-quan-tri-thoat-khoi-cai-bay-kho-chu-trong-kinh-doanh-nha-khoa',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc5e54e1-06ec-4361-aa8f-221c6aef3010','1d0e6877-3178-4f7a-8ac5-c06f77abde13',9,'text','Sai lầm lớn nhất của các bác sĩ khi đứng ra mở phòng khám Nha khoa RHM là tư duy lấy mình làm trung tâm của mọi sự phát triển. Họ nhầm tưởng rằng chỉ cần mình có tay nghề lâm sàng giỏi, tận tụy đầu ghế nha thì phòng khám sẽ tự động tăng trưởng. Tuy nhiên, mô hình phụ thuộc hoàn toàn vào một cá nhân (Founder-Dependent Model) sẽ nhanh chóng chạm trần giới hạn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67aafe98-b183-4a84-8d31-0dfbc5a9ef4f','1d0e6877-3178-4f7a-8ac5-c06f77abde13',10,'text','- Khi Bác sĩ bận cắm Implant, không ai có thể tư vấn và chốt các phác đồ lớn cho tệp khách mới từ kênh TikTok, facebook hay Zalo.- Khi sảnh chờ phóng khám đông khách, hệ thống lập tức bị nghẽn mạch vì Lễ tân không biết phân luồng, Phụ tá thiếu tính chủ động, còn CSKH thì liên tục quên lịch hẹn.- Chủ doanh nghiệp rơi vào trạng thái "khổ chủ" vừa phải gánh chuyên môn y khoa nặng nề, vừa phải kiệt sức xử lý các sự cố vận hành nhân sự vụn vặt hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f32c4339-ab84-4e66-869a-dec327c1e847','1d0e6877-3178-4f7a-8ac5-c06f77abde13',11,'text','**People OS** ra đời trong kiến trúc **Dental Empire** để đập tan chiếc trần kính đó. Hệ điều hành này không tập trung vào việc đi tìm những "ngôi sao cô độc", mà tập trung vào việc **thiết lập hệ thống hạ tầng quản trị con người**. Nó chuyển hóa phòng khám từ một thực thể sống dựa trên năng lượng của người sáng lập thành một bộ máy tự vận hành đồng bộ, chuẩn hóa bằng quy trình, năng lực và kỷ luật tự chủ của cả một đội ngũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('68f94777-7a42-41f1-b7e3-598f6107e4ae','29-people-os','cd04939d-a1ac-4ffe-b783-dfc2b6e21714',3,'Ma Trận Chuyển Dịch: Phụ Thuộc Cá Nhân Vs. Vận Hành Bằng Đội Ngũ','ma-tran-chuyen-dich-phu-thuoc-ca-nhan-vs-van-hanh-bang-oi-ngu',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0527fc3-644c-4553-b418-419094170756','68f94777-7a42-41f1-b7e3-598f6107e4ae',12,'text','Để bứt phá quy mô thương hiệu mà vẫn bảo toàn nguyên vẹn chất lượng y khoa tử tế, bộ máy nhân sự bắt buộc phải dịch chuyển toàn diện qua 3 chiều không gian quản trị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10a5596a-401c-4ed4-9871-01bbbe8db1ad','68f94777-7a42-41f1-b7e3-598f6107e4ae',13,'image',NULL,'book/29-people-os/4d4b1d85-61ed-4a3c-86b7-8efe8a4944ae-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9e3d6b5b-4508-4b11-b4da-e8dcf2f71aa7','29-people-os','cd04939d-a1ac-4ffe-b783-dfc2b6e21714',3,'Sáu Khối Cấu Trúc Lõi Của Hệ Điều Hành People OS','sau-khoi-cau-truc-loi-cua-he-ieu-hanh-people-os',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a66ba6b0-3ee7-4189-bb99-aeec5c8ed299','9e3d6b5b-4508-4b11-b4da-e8dcf2f71aa7',14,'text','Hệ thống quản trị và phát triển nguồn nhân lực của phòng khám được xây dựng dựa trên 6 khối kiến trúc khép kín, đảm bảo không có bất kỳ khoảng trống quản lý nào:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c24602da-656b-4040-ab26-30fc912492ff','9e3d6b5b-4508-4b11-b4da-e8dcf2f71aa7',15,'image',NULL,'book/29-people-os/154a1e81-2f0a-4b5b-903f-b2692b710945-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07cb9a66-d913-43cc-a7f6-0aba4c9af2f4','9e3d6b5b-4508-4b11-b4da-e8dcf2f71aa7',16,'text','- **1. Vai trò (Roles):** Định vị tường minh sơ đồ tổ chức phối hợp chức năng. Mỗi nhân sự bước vào sàn Hà Nội phải biết rõ mình thuộc đường ống nào, báo cáo trực tiếp cho ai và ai là người nghiệm thu kết quả làm việc của mình.- **2. Trách nhiệm (Responsibilities):** Chuẩn hóa Ma trận mô tả công việc (JD) cứng đến từng chi tiết. Tuyệt đối loại bỏ tư duy mập mờ: *"Việc này là của chung"* hoặc *"Tưởng người kia đã làm rồi"*.- **3. Năng lực (Competency Matrix):** Thiết lập Khung tiêu chuẩn kỹ năng cho từng vị trí (Lễ tân, Phụ tá, TCO, Bác sĩ). Đây là thước đo cứng để phòng khám thực hiện công tác tuyển dụng, đào tạo và xét duyệt thăng tiến.- **4. Hiệu suất (Performance - KPI/OKRs):** Số hóa kết quả làm việc hằng ngày của nhân sự lên Dashboard. Mọi đóng góp, kỷ luật hay lỗi sai vận hành đều được ghi nhận bằng con số thực chứng, triệt tiêu sự thiên vị cảm tính.- **5. Đãi ngộ (Compensation):** Thiết kế cơ chế lương thưởng bậc thang và trò chơi hóa hiệu suất (Gamification). Nhân sự làm nhiều, tạo ra thặng dư doanh thu lớn cho Finance OS sẽ nhận được phần thưởng tương xứng, giải phóng tối đa động lực tự thân.- **6. Văn hóa đội ngũ (Operational Culture):** Đồng nhất tư duy y khoa tử tế của Bác sĩ Vinh vào mọi hành vi ứng xử của nhân sự. Biến lòng trắc ẩn, tính trung thực và kỷ luật vô điều kiện thành bản năng hành động của cả tập thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e975bf2b-92fb-4c66-bfc8-0e30df95f9e2','29-people-os','cd04939d-a1ac-4ffe-b783-dfc2b6e21714',3,'Chỉ Số ROI Trên Chi Phí Nhân Sự Và Không Gian Sàn (HCROI_{\\text{clinical}})','chi-so-roi-tren-chi-phi-nhan-su-va-khong-gian-san-hcroitextclinical',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e74a36a-86fc-4bdd-bbc5-3cba219fffda','e975bf2b-92fb-4c66-bfc8-0e30df95f9e2',17,'image',NULL,'book/29-people-os/245ec090-f578-4934-8919-4e336537b00e-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7be1877e-b2a2-4d4c-a043-739153879ef0','e975bf2b-92fb-4c66-bfc8-0e30df95f9e2',18,'text','**Mantra điều hành People OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b66d7d14-e755-45d2-bb87-09006f8bbfaf','e975bf2b-92fb-4c66-bfc8-0e30df95f9e2',19,'text','*"Một phòng khám phụ thuộc vào một ngôi sao sẽ chết khi ngôi sao đó rời đi. Một phòng khám vận hành bằng một hệ thống People OS khoa học sẽ tự động tăng trưởng và sinh sản động năng liên tục. Hãy ngừng quản trị con người bằng cảm xúc và lời nói suông, hãy quản trị bằng cấu trúc năng lực và kỷ luật của các con số thực chứng."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d8183da3-711e-4d8f-900f-36c242aa84fc','29-people-os',NULL,2,'29.2 Vai Trò Chiến Lược Của People OS - Giải Cứu Founder Khỏi Vòng Xoáy Ôm Đồm','292-vai-tro-chien-luoc-cua-people-os-giai-cuu-founder-khoi-vong-xoay-om-om',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d9f6b2e6-39c2-4835-958f-93ac2b97ea5d','d8183da3-711e-4d8f-900f-36c242aa84fc',20,'text','Nỗi đau lớn nhất của đa số chủ phòng khám RHM khi mới mở đó là "đầu tắt mặt tối", luôn bận rộn nhưng phòng khám nhưng không thể bứt phá quy mô. Nếu Marketing OS hay Sales OS là những bộ phận mang tiền về cho phòng khám, thì **People OS** chính là hệ điều hành giải phóng thời gian và tâm trí chủ phóng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6d6e9202-38c8-4243-bde0-75c14e12afa0','d8183da3-711e-4d8f-900f-36c242aa84fc',21,'text','Thay vì đóng vai một "người chữa cháy" vĩ đại chạy quanh phòng khám để giải quyết sự cố, People OS thiết lập một hạ tầng quản trị để tự động trả lời và xử lý triệt để bộ 7 câu hỏi chất vấn hệ  thống dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e0a34e9a-d038-4a65-bdd6-c4369991b07a','29-people-os','d8183da3-711e-4d8f-900f-36c242aa84fc',3,'Ma Trận Giải Quyết Lỗ Hổng Vận Hành Bằng People OS','ma-tran-giai-quyet-lo-hong-van-hanh-bang-people-os',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6603d476-82e6-416f-92f9-834374227359','e0a34e9a-d038-4a65-bdd6-c4369991b07a',22,'image',NULL,'book/29-people-os/b391dfd8-aa7d-444e-b696-1d5af27a704b-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e0be3f5b-6d44-4e0e-8b6f-7ee3d24a408c','29-people-os','d8183da3-711e-4d8f-900f-36c242aa84fc',3,'Chỉ Số Đòn Bẩy Quản Trị Founder (MLI)','chi-so-on-bay-quan-tri-founder-mli',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d8423a2-d61c-4ec9-8973-7f4807fc1d4c','e0be3f5b-6d44-4e0e-8b6f-7ee3d24a408c',23,'image',NULL,'book/29-people-os/2515a54b-9b2d-4ad4-8a1c-5e54c027aa0b-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('68f9d620-0d78-4568-a728-694700727d5f','e0be3f5b-6d44-4e0e-8b6f-7ee3d24a408c',24,'text','**Mantra điều hành vai trò People OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d323b524-26ee-4065-b02b-348b5fb9a24e','e0be3f5b-6d44-4e0e-8b6f-7ee3d24a408c',25,'text','*"Một người chủ phòng khám vĩ đại không phải là người làm thay việc cho tất cả mọi người, mà là người xây dựng được một hệ thống quản trị khiến mọi người tự làm tốt công việc của họ một cách kiêu hãnh. Hãy dùng People OS để đập tan chiếc trần kính ôm đồm, trả lại vị thế nhà chiến lược tối cao cho người điều hành."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2317e7fa-5f1f-42f7-8467-436cd11bedca','29-people-os',NULL,2,'29.3 Bản Đồ Kiến Trúc 8 Lớp Của Hệ Điều Hành People OS','293-ban-o-kien-truc-8-lop-cua-he-ieu-hanh-people-os',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0efd57d1-715f-4726-a597-7699c7037214','2317e7fa-5f1f-42f7-8467-436cd11bedca',26,'text','Để xây dựng một tổ chức nha khoa tự vận hành, giải phóng người chủ khỏi vòng xoáy quản trị thủ công, **People OS** được cấu trúc thành 8 cấu phần cốt lõi. Đây là tháp hạ tầng hoàn chỉnh giúp phòng khám đóng gói năng lực tổ chức, tuyển dụng đúng người, giữ chân người tài và kích nổ hiệu suất làm việc của toàn bộ đội ngũ trực sàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b50a9b92-ae65-4dc0-9aa4-f2022f571323','29-people-os','2317e7fa-5f1f-42f7-8467-436cd11bedca',3,'Sơ Đồ Hệ Thống Kiến Trúc People OS (8-Layer Human Resources Stack)','so-o-he-thong-kien-truc-people-os-8-layer-human-resources-stack',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3f18ecf-3c60-48a4-8a2a-8ca9c459acfd','b50a9b92-ae65-4dc0-9aa4-f2022f571323',27,'image',NULL,'book/29-people-os/9ebb1995-eb26-4e6f-b6c4-561b3778f1f2-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('84bdbffe-7553-4311-b451-d902658c7674','29-people-os','2317e7fa-5f1f-42f7-8467-436cd11bedca',3,'Bóc Tách Chi Tiết 8 Phần Cốt Lõi Trong Vận Hành','boc-tach-chi-tiet-8-phan-cot-loi-trong-van-hanh',12,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b89abcf0-dea5-4e45-b433-d2da08f8e34a','29-people-os','84bdbffe-7553-4311-b451-d902658c7674',4,'1. Organization Chart (Sơ đồ tổ chức phòng khám)','1-organization-chart-so-o-to-chuc-phong-kham',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8e2c47c6-a4a9-484f-81e0-40e6c8216e62','b89abcf0-dea5-4e45-b433-d2da08f8e34a',28,'text','- **Bản chất:** Phân định rõ ràng ranh giới giữa Khối Lâm sàng (Bác sĩ điều trị, Phụ tá, Vô trùng) và Khối Vận hành Kinh doanh (Lễ tân, Chuyên viên tư vấn TCO, CSKH, Marketing, Kế toán).- **Mục tiêu quản trị:** Xác lập trục dọc quyền lực (Tuyến báo cáo) và trục ngang phối hợp (Đường đi của hồ sơ bệnh nhân), đảm bảo mọi nhân sự đều biết ai là cấp trên trực tiếp của mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ba268da1-ed96-4e1c-a0e5-2d3d6485db12','29-people-os','84bdbffe-7553-4311-b451-d902658c7674',4,'2. Role &amp; Responsibility (Vai trò &amp; Trách nhiệm cụ thể)','2-role-amp-responsibility-vai-tro-amp-trach-nhiem-cu-the',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26875ad0-db8b-41ad-8a5a-89245a1ceac0','ba268da1-ed96-4e1c-a0e5-2d3d6485db12',29,'text','- **Bản chất:** Đóng gói toàn bộ mô tả công việc (JD) của từng vị trí dựa trên kết quả đầu ra cam kết (SLA), thay vì mô tả hành động chung chung.- **Mục tiêu quản trị:** Áp dụng ma trận phân quyền để làm rõ: Ai là người trực tiếp làm, ai là người chịu trách nhiệm nghiệm thu cuối cùng, ai là người cần phối hợp và ai là người cần nhận thông tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8fd3af68-5c67-49b5-9fbd-84626a1df3ac','29-people-os','84bdbffe-7553-4311-b451-d902658c7674',4,'3. Hiring System (Hệ thống tuyển dụng chuẩn hóa)','3-hiring-system-he-thong-tuyen-dung-chuan-hoa',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9bb106c4-ae6e-4c91-98e7-a08681a6db13','8fd3af68-5c67-49b5-9fbd-84626a1df3ac',30,'text','- **Bản chất:** Thiết lập bộ lọc tuyển dụng chủ động, xây dựng chân dung nhân sự lý tưởng (Persona) cho ngành nha khoa.- **Mục tiêu quản trị:** Triệt tiêu tư duy "đợi thiếu mới tuyển". Hệ thống bao gồm bộ câu hỏi phỏng vấn hành vi, bài test năng lực xử lý tình huống sảnh chờ và bài kiểm tra tay nghề lâm sàng bắt buộc đối với bác sĩ/phụ tá.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3689bb19-cc80-41e8-a523-8ee8f92a3182','29-people-os','84bdbffe-7553-4311-b451-d902658c7674',4,'4. Onboarding System (Hệ thống hội nhập nhân sự mới)','4-onboarding-system-he-thong-hoi-nhap-nhan-su-moi',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c7b166a6-b488-4993-83c3-227cb7974e61','3689bb19-cc80-41e8-a523-8ee8f92a3182',31,'text','- **Bản chất:** Thiết kế kịch bản thử việc trong 30-60-90 ngày đầu tiên của nhân sự mới bước vào phòng khám.- **Mục tiêu quản trị:** Tránh hiện tượng "đem con bỏ chợ". Mỗi nhân sự mới đều có một người hướng dẫn (Buddy) kèm cặp, có Checklist đầu việc cần hoàn thành theo tuần để tự đánh giá mức độ phù hợp văn hóa và áp lực công việc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('48358c2f-3f72-4ff2-981a-7b5f2ee27baa','29-people-os','84bdbffe-7553-4311-b451-d902658c7674',4,'5. Training System (Hệ thống đào tạo nội bộ liên tục)','5-training-system-he-thong-ao-tao-noi-bo-lien-tuc',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8419961c-40dd-47ae-8ac1-e7a12f18261a','48358c2f-3f72-4ff2-981a-7b5f2ee27baa',32,'text','- **Bản chất:** Trục nâng cấp năng lực cho bộ máy. Chia làm hai nhánh: Đào tạo tay nghề y khoa (cho khối lâm sàng) và Đào tạo kỹ năng điểm chạm, kịch bản giao tiếp (cho khối sảnh/tư vấn).- **Mục tiêu quản trị:** Đảm bảo dù phòng khám có thay đổi nhân sự thì chất lượng điều trị và dịch vụ chăm sóc vẫn giữ nguyên một tiêu chuẩn đồng nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('322c208c-a102-4eed-82b7-26f38bde51c6','29-people-os','84bdbffe-7553-4311-b451-d902658c7674',4,'6. Performance Management (Quản trị hiệu suất dựa trên số liệu)','6-performance-management-quan-tri-hieu-suat-dua-tren-so-lieu',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0aa85e1b-2dbb-43bd-8d48-ea05aa90332b','322c208c-a102-4eed-82b7-26f38bde51c6',33,'text','- **Bản chất:** Hệ thống màng lọc đánh giá đóng góp thực tế của từng nhân sự dựa trên các chỉ số định lượng, kết nối trực tiếp với CRM của phòng khám.- **Mục tiêu quản trị:** Triệt tiêu hoàn toàn việc đánh giá nhân viên bằng cảm tính, yêu ghét cá nhân. Ai làm tốt, tạo ra chỉ số chuyển đổi cao sẽ được ghi nhận hiển thị trực quan trên Dashboard.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1c3227b8-bc6d-404f-aafa-8a4a0131963c','29-people-os','84bdbffe-7553-4311-b451-d902658c7674',4,'7. Compensation &amp; Incentive (Hệ thống đãi ngộ &amp; Khen thưởng thông minh)','7-compensation-amp-incentive-he-thong-ai-ngo-amp-khen-thuong-thong-minh',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ad9235d9-0e60-49b8-8ab4-1bef49771fc0','1c3227b8-bc6d-404f-aafa-8a4a0131963c',34,'text','- **Bản chất:** Cơ chế chia sẻ lợi ích kinh tế (Performance Pay) được thiết kế theo mô hình 3P: Lương theo vị trí (Position), Lương theo năng lực (Person) và Thưởng theo hiệu suất thực tế (Performance).- **Mục tiêu quản trị:** Gắn chặt túi tiền của nhân viên vào sự sống còn của phòng khám. Khi nhân sự tối ưu được chi phí Labo, tăng tỷ lệ chốt phác đồ hoặc kéo dài vòng đời bệnh nhân, thu nhập của họ sẽ tự động tăng tương ứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2fb0a048-cbde-4655-ba41-39e0394a89da','29-people-os','84bdbffe-7553-4311-b451-d902658c7674',4,'8. Culture &amp; Meeting Rhythm (Văn hóa &amp; Nhịp điệu hội họp)','8-culture-amp-meeting-rhythm-van-hoa-amp-nhip-ieu-hoi-hop',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c16ad5b1-25de-43b8-9975-c4b4c3683f5f','2fb0a048-cbde-4655-ba41-39e0394a89da',35,'text','- **Bản chất:** Hệ thống thiết lập nhịp đập vận hành cho tổ chức thông qua các cuộc họp định kỳ: Daily Standup (Họp nhanh đầu ngày 10 phút), Weekly Sync (Giao ban tuần xử lý điểm nghẽn) và Monthly Review (Khóa sổ chiến lược tháng).- **Mục tiêu quản trị:** Giữ cho toàn bộ bộ máy luôn đồng bộ thông tin, cùng nhìn về một hướng và duy trì văn hóa y khoa tử tế, trung thực tuyệt đối trước bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('96130d7e-543c-4981-958e-db8eec74f690','29-people-os','2317e7fa-5f1f-42f7-8467-436cd11bedca',3,'Chỉ Số Năng Suất Lao Động (SPI)','chi-so-nang-suat-lao-ong-spi',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c1daaf4-8882-4f6f-b5c5-739e6ae0eee0','96130d7e-543c-4981-958e-db8eec74f690',36,'image',NULL,'book/29-people-os/4e7120b5-3665-40f8-bf79-10912ef8e9b7-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('449c974e-2531-41a3-a439-4fc118fb7948','96130d7e-543c-4981-958e-db8eec74f690',37,'text','**Mantra điều hành cấu trúc People OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8d55305-2970-450e-8d85-8ca583cfcdf5','96130d7e-543c-4981-958e-db8eec74f690',38,'text','*"Kiến trúc 8 phần của People OS hoạt động như một vòng bánh răng khép kín. Tuyển sai người ở khâu Hiring sẽ làm nát khâu Training; quản trị lỏng lẻo ở khâu Performance sẽ triệt tiêu động lực ở khâu Compensation. Hãy đặt từng viên gạch quy trình này với sự chuẩn xác như khi bạn đang thực hiện một ca phẫu thuật lâm sàng."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('db34c116-8721-4dd0-9810-dc617b18c374','29-people-os',NULL,2,'29.4 Sơ đồ tổ chức trong Dental Empire','294-so-o-to-chuc-trong-dental-empire',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9eac16d1-cd6a-4c01-bd48-05afad9e05fb','db34c116-8721-4dd0-9810-dc617b18c374',39,'image',NULL,'book/29-people-os/668a5122-4fef-4967-852a-f7c62b48f13b-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c96df8c2-3403-4f04-b0f9-ad4b05073b8b','29-people-os',NULL,2,'29.5 Role &amp; Responsibility - Ma Trận Phân Định Vai Trò Và Trách Nhiệm Bộ Máy Nha Khoa','295-role-amp-responsibility-ma-tran-phan-inh-vai-tro-va-trach-nhiem-bo-may-nha-k',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d4d77b4-208d-4a2c-86c2-c88be48ece92','c96df8c2-3403-4f04-b0f9-ad4b05073b8b',40,'text','Sự hỗn loạn trong vận hành phòng khám thường bắt nguồn từ việc mập mờ trong phân công trách nhiệm. Khi một sự cố xảy ra (ví dụ: bệnh nhân phàn nàn, dữ liệu CRM bị sai lệch, hoặc công nợ trả góp bị chậm thu hồi), nhân sự có xu hướng đổ lỗi chéo cho nhau do không có một ranh giới trách nhiệm rõ ràng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d076f393-2663-479f-879a-7c0b52c5cde2','c96df8c2-3403-4f04-b0f9-ad4b05073b8b',41,'text','Phân hệ **Role & Responsibility** thuộc *People OS* thực hiện nhiệm vụ đóng gói cấu trúc công việc của 8 vị trí cốt lõi trong một phòng khám nha khoa tiêu chuẩn. Hệ thống chuyển dịch từ cách quản lý hành vi sang **quản trị theo kết quả đầu ra (SLA)**, đảm bảo mỗi vị trí là một mắt xích độc lập, tự chủ và có thể đo lường sòng phẳng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7d9df3cf-06f6-491e-8a8d-c95bd68261cd','29-people-os','c96df8c2-3403-4f04-b0f9-ad4b05073b8b',3,'Ma Trận Định Danh Trách Nhiệm Của 8 Vị Trí Cốt Lõi In-Clinic','ma-tran-inh-danh-trach-nhiem-cua-8-vi-tri-cot-loi-in-clinic',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b7c05a6-1e0b-4ab3-9b63-a41ee3acb048','7d9df3cf-06f6-491e-8a8d-c95bd68261cd',42,'text','Mỗi vị trí bước vào sơ đồ vận hành phòng khám bắt buộc phải gánh vác các trường trách nhiệm cứng dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e476c75-2411-4034-ad94-2bd338493b23','7d9df3cf-06f6-491e-8a8d-c95bd68261cd',43,'image',NULL,'book/29-people-os/85449df4-f959-45ce-82dd-064fe5d61ae4-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('97f8cb56-f6ba-4949-9e91-8c6d05f16325','29-people-os','c96df8c2-3403-4f04-b0f9-ad4b05073b8b',3,'Chỉ Số Rõ Ràng Về Trách Nhiệm Tổ Chức (RCI)','chi-so-ro-rang-ve-trach-nhiem-to-chuc-rci',25,'[]');
