INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('756a7fca-aaf5-4c20-a1a3-c2946a196c51','97f8cb56-f6ba-4949-9e91-8c6d05f16325',45,'text','**Mantra điều hành Role & Responsibility:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b78da593-a0d6-44ab-871a-f293a14ea436','97f8cb56-f6ba-4949-9e91-8c6d05f16325',46,'text','*"Mọi người cùng chịu trách nhiệm nghĩa là không ai chịu trách nhiệm cả. Một bộ máy nha khoa tinh nhuệ là nơi mà mỗi nhân sự bước vào sàn đều hiểu rõ ranh giới quyền lực và cam kết đầu ra của chính mình một cách tuyệt đối. Hãy dùng ma trận trách nhiệm để trả tự do cho nhà quản lý và kích nổ tính chủ động của tập thể."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('06e57975-84e5-4515-b472-b4ec1b58e595','29-people-os','c96df8c2-3403-4f04-b0f9-ad4b05073b8b',3,'RACI Matrix cho Dental Empire','raci-matrix-cho-dental-empire',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('537d0be0-f6fa-484f-b00f-38082649afbd','06e57975-84e5-4515-b472-b4ec1b58e595',47,'image',NULL,'book/29-people-os/3decb175-6b1d-46b6-b56b-7040143d3b77-img13.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('737b618e-5237-4819-9f86-d9fc499e6bb2','29-people-os',NULL,2,'29.6 Hiring System - Hệ Thống Tuyển Dụng Chuẩn Hóa Khối Nha Khoa','296-hiring-system-he-thong-tuyen-dung-chuan-hoa-khoi-nha-khoa',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8633a6cf-22f8-4c31-a851-d4e51cf43df1','737b618e-5237-4819-9f86-d9fc499e6bb2',48,'text','Một trong các lỗi khi làm tuyển dụng là tư duy "thủng đâu vá đấy" đợi đến khi phụ tá nghỉ việc hoặc sảnh chờ quá tải mới cuống cuồng đăng tin tuyển người. Việc tuyển dụng trong trạng thái khẩn cấp khiến phòng khám dễ thỏa hiệp với những nhân sự kém năng lực, từ đó phá nát chất lượng dịch vụ và y khoa đầu ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39b27954-53ff-4e2f-b29b-e5111b824abc','737b618e-5237-4819-9f86-d9fc499e6bb2',49,'text','Trong hệ điều hành **People OS**, tuyển dụng không phải là một hoạt động hành chính bị động. Đây là **hệ thống màng lọc chủ động** nhằm tìm kiếm, thẩm định và chiêu mộ những mảnh ghép phù hợp nhất với từng chặng tăng trưởng của doanh nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2f2b2fce-26b1-47b8-82f1-6327ffd3c718','29-people-os','737b618e-5237-4819-9f86-d9fc499e6bb2',3,'Ma Trận Định Biên Và Vị Trí Ưu Tiên Theo Giai Đoạn Phát Triển','ma-tran-inh-bien-va-vi-tri-uu-tien-theo-giai-oan-phat-trien',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f30520b-0e06-4f82-86d5-09b7d31a8d48','2f2b2fce-26b1-47b8-82f1-6327ffd3c718',50,'text','Mỗi quy mô phòng khám đòi hỏi một cấu trúc nhân sự khác nhau. Việc ôm đồm tuyển dụng các vị trí cấp cao quá sớm sẽ làm phình to định phí, ngược lại, chậm chạp trong việc nâng cấp đội ngũ khi đang tăng trưởng sẽ tự làm nghẽn mạch bánh đà doanh thu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6cc84493-7a75-4137-a95a-c5fb82c7e051','2f2b2fce-26b1-47b8-82f1-6327ffd3c718',51,'image',NULL,'book/29-people-os/9684cb34-a153-4678-a7e0-686591ccb515-img14.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('09978a56-7b5a-4374-a397-cadb4073c1b0','29-people-os','737b618e-5237-4819-9f86-d9fc499e6bb2',3,'Quy Trình Tuyển Dụng Khép Kín Truy Vết 10 Bước','quy-trinh-tuyen-dung-khep-kin-truy-vet-10-buoc',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb22647f-8bfd-4c7f-8170-bb83f014307d','09978a56-7b5a-4374-a397-cadb4073c1b0',52,'text','Để triệt tiêu hoàn toàn tỷ lệ tuyển sai người, đường ống tuyển dụng của phòng khám bắt buộc phải đi qua 10 chặng kiểm duyệt nghiêm ngặt:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9dbbaec0-5855-4db7-940a-5819660e2428','09978a56-7b5a-4374-a397-cadb4073c1b0',53,'image',NULL,'book/29-people-os/1ae363e2-5f2a-48c9-bdcb-2ee0c9f6f7c1-img15.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fb4f9c86-9b51-458e-853c-73cf14dc37b8','29-people-os','737b618e-5237-4819-9f86-d9fc499e6bb2',3,'Chỉ Số Tỷ Lệ Sống Sót Thử Việc Chặng Ngắn (TSR)','chi-so-ty-le-song-sot-thu-viec-chang-ngan-tsr',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d9fceb27-c2b5-4bd8-addb-f5e7c9af3540','fb4f9c86-9b51-458e-853c-73cf14dc37b8',54,'text','Để đo lường độ chính xác của hệ thống màng lọc tuyển dụng và kiểm soát chi phí chìm phát sinh khi đào tạo nhầm người, bộ phận nhân sự bắt buộc phải theo dõi chỉ số **Tỷ lệ sống sót thử việc (Trial Survival Rate - ****TSR****)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc38f7f3-bdf2-4c6b-8396-ffec6f4e9568','fb4f9c86-9b51-458e-853c-73cf14dc37b8',55,'text','TSR (\\%) = \\left( \\frac{\\text{Số nhân sự vượt qua mốc đánh giá 30 ngày và ký chính thức}}{\\text{Tổng số nhân sự được nhận vào thử việc trong kỳ}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('40aaa633-3604-46bf-8291-bd71175001d1','fb4f9c86-9b51-458e-853c-73cf14dc37b8',56,'text','- **Ngưỡng an toàn tiêu chuẩn:** Chỉ số TSR bắt buộc phải duy trì ở mức **\\ge 80\\%**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef709e1f-299b-404d-ba2d-df2a2c59069c','fb4f9c86-9b51-458e-853c-73cf14dc37b8',57,'text','**Hành động sửa sai:** Nếu chỉ số này tụt xuống dưới mức 60%, chứng tỏ hệ thống tuyển dụng đang bị lỗi nghiêm trọng ở khâu Sàng lọc CV (Bước 4) hoặc Test năng lực tình huống (Bước 6), dẫn đến việc đưa người sai tiêu chuẩn vào bộ máy làm mất thời gian và chi phí vận hành. Chủ phòng khám phải yêu cầu siết lại bộ tiêu chuẩn phỏng vấn ngay lập tức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29f70a05-171e-4929-af1d-0abb1c0c42df','fb4f9c86-9b51-458e-853c-73cf14dc37b8',58,'image',NULL,'book/29-people-os/293e0adf-5a72-47bd-aa8d-c7da781c071d-img16.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('068b8c69-5b34-4c5a-950d-53983fe52e47','fb4f9c86-9b51-458e-853c-73cf14dc37b8',59,'text','**Mantra điều hành Hiring System:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f15f7afe-4e3e-4868-ad50-6165e4f3742f','fb4f9c86-9b51-458e-853c-73cf14dc37b8',60,'text','*"Tuyển dụng chậm rãi nhưng sa thải nhanh chóng. Thà để trống một vị trí ghế nha và chấp nhận giảm công suất tạm thời, còn hơn tuyển nhầm một nhân sự độc hại hoặc yếu chuyên môn để rồi phá nát lòng tin của hàng trăm bệnh nhân. Hãy biến hệ thống tuyển dụng thành màng lọc danh giá nhất của phòng khám."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f9b314cf-8127-44cd-a0c3-0a6e955d7eec','29-people-os',NULL,2,'29.7 Onboarding System - Hệ Thống Hội Nhập Và Ramp-Up Nhân Sự Mới','297-onboarding-system-he-thong-hoi-nhap-va-ramp-up-nhan-su-moi',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1841aa73-ad87-4664-b614-7b7b3dac57d9','f9b314cf-8127-44cd-a0c3-0a6e955d7eec',61,'text','Hiện tượng "đem con bỏ chợ" là một vết xe đổ rất phổ biến tại các phòng khám nha khoa quy mô vừa và nhỏ. Nhân sự mới (dù là lễ tân, phụ tá hay bác sĩ) sau khi vượt qua vòng phỏng vấn thường chỉ được phát cho một tập tài liệu sơ sài, rồi ngay lập tức bị ném vào guồng quay bận rộn của sảnh chờ và ghế nha. Hệ quả là họ bị "ngợp" trước áp lực lâm sàng, làm sai quy trình ảnh hưởng đến trải nghiệm bệnh nhân, và tỷ lệ xin nghỉ việc trong 30 ngày đầu tiên tăng cao kỷ lục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66738f9d-6fe3-42a8-ae8e-d46f1a888782','f9b314cf-8127-44cd-a0c3-0a6e955d7eec',62,'text','Trong hệ điều hành **People OS**, hội nhập (Onboarding) là một **đường ống tăng tốc năng suất (Ramp-up Pipeline)** được thiết kế khoa học. Mục tiêu tối cao là dịch chuyển nhân sự mới từ trạng thái "tiêu tốn tài nguyên đào tạo" sang trạng thái "tự chủ vận hành và tạo ra giá trị kinh tế" cho phòng khám trong thời gian ngắn nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a4117667-3c0a-4605-a23f-f53e7b20d7a6','29-people-os','f9b314cf-8127-44cd-a0c3-0a6e955d7eec',3,'Ma Trận Checklist Hội Nhập Tiêu Chuẩn 30 Ngày (The 30-Day Onboarding Matrix)','ma-tran-checklist-hoi-nhap-tieu-chuan-30-ngay-the-30-day-onboarding-matrix',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('91c04ee6-6054-4423-9c0e-f77763f9e500','a4117667-3c0a-4605-a23f-f53e7b20d7a6',63,'text','Hạ tầng hội nhập bắt buộc phải được đóng gói thành một bộ Checklist đóng cứng, chia nhỏ theo từng cột mốc thời gian để người quản lý cơ sở và nhân sự hướng dẫn (Buddy) nghiệm thu hằng ngày:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5bc35409-1f89-46f3-8636-1f3a4e6d281e','a4117667-3c0a-4605-a23f-f53e7b20d7a6',64,'image',NULL,'book/29-people-os/5627fe8f-5f5f-4008-9d5a-0e8002b48cfc-img17.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e3981f47-369e-46fb-b510-c5b7ae2d16cc','29-people-os','f9b314cf-8127-44cd-a0c3-0a6e955d7eec',3,'Cơ Chế Vận Hành "Buddy System" (Bạn Đồng Hành Lâm Sàng)','co-che-van-hanh-buddy-system-ban-ong-hanh-lam-sang',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fa719597-31f5-440d-bc3f-df5dabb3bdea','e3981f47-369e-46fb-b510-c5b7ae2d16cc',65,'text','Để Checklist 30 ngày trên không biến thành một tờ giấy lộn, phòng khám bắt buộc phải áp dụng cơ chế **Buddy System**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('59ba79d6-0418-4d98-87d3-6a5db50b1aaa','e3981f47-369e-46fb-b510-c5b7ae2d16cc',66,'text','- Mỗi nhân sự mới bước vào sàn phải được chỉ định một nhân sự cũ có kinh nghiệm làm "Người đồng hành" (Buddy).- Buddy chịu trách nhiệm hướng dẫn thực địa, giải đáp thắc mắc và ký nghiệm thu Checklist hằng ngày cho nhân sự mới.- *Kích thích động lực:* Nếu nhân sự mới vượt qua thử việc thành công và đạt chỉ số năng suất chuẩn, Buddy sẽ được hệ thống **Finance OS** chi trả một khoản thưởng nóng (Coaching Bonus) để ghi nhận công sức đào tạo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7d3c4137-070c-4761-81e3-ab3349b49890','29-people-os','f9b314cf-8127-44cd-a0c3-0a6e955d7eec',3,'Chỉ Số Thời Gian Đạt Năng Suất Chuẩn (TTP)','chi-so-thoi-gian-at-nang-suat-chuan-ttp',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47a05a9a-24e1-4e30-802f-1a170ff5f7e6','7d3c4137-070c-4761-81e3-ab3349b49890',67,'text','Để tối ưu hóa chi phí vận hành và thẩm định độ hiệu quả của đường ống hội nhập, chủ phòng khám cần giám sát chặt chẽ chỉ số **Thời gian đạt năng suất tiêu chuẩn (Time to Productivity - ****TTP****)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('75f94cda-b3f6-49e5-8112-faabb5b28a78','7d3c4137-070c-4761-81e3-ab3349b49890',68,'text','TTP \\text{ (Ngày)} = \\text{Ngày nhân sự chính thức đạt } 100\\% \\text{ KPI thử nghiệm} - \\text{Ngày đầu tiên nhận việc}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff6bdc76-fe2d-46e6-9363-40a3b0095ed0','7d3c4137-070c-4761-81e3-ab3349b49890',69,'text','**Định mức an toàn hệ thống Nha khoa tiêu chuẩn:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d4c9a54-5d82-4244-b4d8-989d456df67f','7d3c4137-070c-4761-81e3-ab3349b49890',70,'text','- Đối với khối Lễ tân / Phụ tá / CSKH: Chỉ số TTP bắt buộc phải **\\le 21**** ngày**.- Đối với khối Bác sĩ hợp tác / Chuyên viên tư vấn phác đồ (TCO): Chỉ số TTP bắt buộc phải **\\le 30**** ngày**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48b549ed-fb95-41b7-bd05-3daffb235551','7d3c4137-070c-4761-81e3-ab3349b49890',71,'text','**Hành động sửa sai:** Nếu chỉ số TTP trung bình của phòng khám kéo dài vượt quá 45 ngày, chứng tỏ hệ thống hội nhập đang quá lỏng lẻo hoặc tài liệu quy trình quá mơ hồ. Phòng khám đang phải bù lỗ chi phí lương thử việc cho những nhân sự chưa tạo ra giá trị. Quản lý cơ sở phải lập tức siết lại khâu huấn luyện Tuần 1 và Tuần 2 ngay trong chu kỳ kế tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e96dc0b8-0c29-4de2-8625-d142f9597daa','7d3c4137-070c-4761-81e3-ab3349b49890',72,'image',NULL,'book/29-people-os/d385b90c-1423-44de-8e41-429a6ecff75c-img18.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2f83ec5c-bdb7-4838-8899-2ea186320faf','7d3c4137-070c-4761-81e3-ab3349b49890',73,'text','**Mantra điều hành Onboarding System:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('121a0ea3-0f63-4132-969e-421045cb7de7','7d3c4137-070c-4761-81e3-ab3349b49890',74,'text','*"Cách chúng ta đối xử với nhân sự trong 30 ngày đầu tiên sẽ quyết định cách họ đối xử với bệnh nhân trong 3 năm kế tiếp. Đừng mong đợi một đội ngũ trung thành và tinh nhuệ nếu bạn chào đón họ bằng sự hỗn loạn và thiếu quy trình. Hãy biến tháng đầu tiên của họ thành một hành trình được lập trình sẵn cho sự thành công."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('411ff4ee-eda7-477a-9189-3e3c05a5e41d','29-people-os',NULL,2,'29.8 Training System - Hệ Thống Đào Tạo Nội Bộ Liên Tục','298-training-system-he-thong-ao-tao-noi-bo-lien-tuc',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b83c1293-6976-470a-935d-b00a8670d918','411ff4ee-eda7-477a-9189-3e3c05a5e41d',75,'text','Nếu hệ thống hội nhập (Onboarding) giúp nhân sự mới sống sót trong 30 ngày đầu tiên, thì hệ thống đào tạo liên tục (Continuous Training) chính là bệ phóng giúp toàn bộ bộ máy nâng cấp năng lực hằng tuần. Nhiều chủ phòng khám thường phàn nàn: *"Nhân viên năng lực yếu, làm việc hay sai sót"*, nhưng khi kiểm tra lại thì phòng khám hoàn toàn không có giáo trình đào tạo, hoặc chỉ đào tạo theo kiểu "nhắc nhở khi có lỗi sai".',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d4bf15a-a507-4efc-8811-13e93304eb18','411ff4ee-eda7-477a-9189-3e3c05a5e41d',76,'text','Hạ tầng **Training System** trong People OS vận hành như một nhà máy sản xuất kỹ năng. Hệ thống chia tách năng lực phòng khám thành 7 module đào tạo bắt buộc, thiết kế chuyên biệt cho từng khối phòng ban để đảm bảo chất lượng lâm sàng và dịch vụ luôn đạt trạng thái đồng nhất tuyệt đối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0952ce9f-9223-4a27-893a-90567b728001','29-people-os','411ff4ee-eda7-477a-9189-3e3c05a5e41d',3,'Ma Trận 7 Khối Kiến Thức Đào Tạo Tiêu Chuẩn Trong Nha Khoa','ma-tran-7-khoi-kien-thuc-ao-tao-tieu-chuan-trong-nha-khoa',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d21a086-2e3d-43a0-9663-740a4a887284','0952ce9f-9223-4a27-893a-90567b728001',77,'text','Mọi nhân sự trực sàn, từ khối lâm sàng đến khối vận hành kinh doanh, đều phải đi qua các trục đào tạo định kỳ được số hóa dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b94341dd-da34-4897-b988-03cc790b6b49','29-people-os','411ff4ee-eda7-477a-9189-3e3c05a5e41d',3,'','',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bae27c1-8e59-4c53-b921-54824cad7b76','b94341dd-da34-4897-b988-03cc790b6b49',78,'image',NULL,'book/29-people-os/5d224623-6c96-4139-8c88-a54db6caf6cd-img19.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1b02d467-bb80-4003-84df-7346a0fe04d1','29-people-os','411ff4ee-eda7-477a-9189-3e3c05a5e41d',3,'Chỉ Số Hiệu Quả Đào Tạo (TEI)','chi-so-hieu-qua-ao-tao-tei',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1338f564-9f31-40a7-9eb2-64cedc8b4e30','1b02d467-bb80-4003-84df-7346a0fe04d1',79,'text','Để tránh việc đào tạo lý thuyết suông gây lãng phí thời gian, phòng khám bắt buộc phải đo lường chất lượng huấn luyện thông qua **Chỉ số Hiệu quả Đào tạo (Training Effectiveness Index - ****TEI****)** dựa trên hoạt động kiểm toán (Audit) thực địa:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22bb14a8-c355-4cc6-973f-6c628adcfffa','1b02d467-bb80-4003-84df-7346a0fe04d1',80,'text','TEI (\\%) = \\left( \\frac{\\text{Số quy trình thực thi chuẩn xác sau đào tạo}}{\\text{Tổng số quy trình được kiểm toán ngẫu nhiên}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10c83eae-9e3d-4e70-a0c4-e17c7b995d2a','1b02d467-bb80-4003-84df-7346a0fe04d1',81,'text','**Định mức an toàn năng lực tổ chức:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c07f73a2-c19d-4a45-aff4-9024e5a7b78c','1b02d467-bb80-4003-84df-7346a0fe04d1',82,'text','- **Ngưỡng đạt tiêu chuẩn:** Chỉ số TEI của bất kỳ bộ phận nào sau đào tạo bắt buộc phải đạt **\\ge 90\\%**.- **Hành động sửa sai:** Nếu kết quả kiểm toán ngẫu nhiên cho thấy chỉ số TEI tụt xuống dưới 80%, lỗi nằm ở khâu thiết kế tài liệu hoặc người hướng dẫn làm chưa nghiêm túc. Nhân sự bộ phận đó bắt buộc phải bị đình chỉ tăng lương hiệu suất, đồng thời Quản lý cơ sở phải tổ chức tái đào tạo và sát hạch lại trong vòng 7 ngày làm việc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a023ffce-5157-45e7-8321-72aca193a48f','1b02d467-bb80-4003-84df-7346a0fe04d1',83,'image',NULL,'book/29-people-os/126fee11-bf2c-4a49-a95d-61535b04b244-img20.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3385de9-d6dd-4607-9925-53b8df441b1c','1b02d467-bb80-4003-84df-7346a0fe04d1',84,'text','**Mantra điều hành Training System:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02f573bd-4ba1-4c1a-888a-0f94d61b1719','1b02d467-bb80-4003-84df-7346a0fe04d1',85,'text','*"Nhiều chủ phòng khám sợ rằng đào tạo xong nhân viên sẽ nghỉ việc và mang theo bí kíp. Nhưng có một điều còn đáng sợ hơn rất nhiều: Bạn không đào tạo họ, và họ chọn ở lại phòng khám của bạn mãi mãi với một năng lực yếu kém. Hãy biến đào tạo thành hơi thở hằng tuần để thanh lọc và nâng cấp tổ chức."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e2474534-3dd0-44c4-89e2-b50d68f87e0d','29-people-os',NULL,2,'29.9 Performance Management - Quản Trị Hiệu Suất Dựa Trên Số Liệu Thực Chứng','299-performance-management-quan-tri-hieu-suat-dua-tren-so-lieu-thuc-chung',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85ca8175-890d-459e-8d22-763137fc73d7','e2474534-3dd0-44c4-89e2-b50d68f87e0d',86,'text','Một trong những nguyên nhân lớn nhất gây mất đoàn kết nội bộ và triệt tiêu động lực làm việc trong phòng khám nha khoa là cơ chế đánh giá nhân sự bằng cảm tính (yêu ghét cá nhân, đánh giá dựa trên ấn tượng nhất thời). Khi không có thước đo định lượng, nhân sự làm tốt sẽ cảm thấy bị bất công, còn nhân sự yếu kém sẽ tìm cách lấp liếm bằng các báo cáo định tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa3a8e49-b497-4c5b-80c9-5b096ef69a0a','e2474534-3dd0-44c4-89e2-b50d68f87e0d',87,'text','Hệ thống **Performance Management** trong People OS thiết lập một màng lọc kiểm toán năng lực sòng phẳng. Hệ thống này số hóa toàn bộ đóng góp của nhân sự lên Dashboard thông qua các chỉ số định lượng, kết nối trực tiếp với dữ liệu thời gian thực từ CRM và Finance OS.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ec080f65-a83c-485e-acad-bd263df87245','29-people-os','e2474534-3dd0-44c4-89e2-b50d68f87e0d',3,'Tam Giác Vàng: Nguyên Tắc Đánh Giá Nhân Sự Toàn Diện','tam-giac-vang-nguyen-tac-anh-gia-nhan-su-toan-dien',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ac8a5418-54ea-4b83-bd2d-cadd742e028e','ec080f65-a83c-485e-acad-bd263df87245',88,'text','Để đưa ra một phác đồ nhân sự chuẩn xác, phòng khám tuyệt đối không chỉ nhìn vào một góc của vấn đề. Hiệu suất tổng thể của một nhân sự trực sàn phải là sự giao thoa bắt buộc của 3 đỉnh tam giác:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('16ed22f8-d24a-4844-9c61-645f831d0599','ec080f65-a83c-485e-acad-bd263df87245',89,'text','Performance\\ Score = (K \\times w_k) + (H \\times w_h) + (V \\times w_v)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd8dd306-0837-4615-a19c-7b6d584ecef9','ec080f65-a83c-485e-acad-bd263df87245',90,'text','*Trong đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8eb10a41-7820-4c9a-b193-1842ca24d50d','ec080f65-a83c-485e-acad-bd263df87245',91,'text','- K *(Kết quả công việc)*: Các con số KPI định lượng thực tế mà nhân sự đạt được trong tháng.- H *(Hành vi / Thái độ)*: Kỷ luật tuân thủ giờ giấc, tính chủ động đầu ghế nha và tinh thần trách nhiệm với bệnh nhân.- V *(Mức độ phù hợp văn hóa)*: Tỷ lệ đồng điệu với triết lý y khoa tử tế, tính trung thực tuyệt đối trong điều trị và năng lực phối hợp liên phòng ban.- w_k, w_h, w_v: Trọng số ưu tiên thay đổi linh hoạt theo đặc thù của từng khối phòng ban (Ví dụ: Khối Sales/Marketing sẽ nặng trọng số w_k, khối Lâm sàng/Vô trùng sẽ nặng trọng số w_h và w_v).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c18f888c-e680-490b-b5ee-0f2efa44fc21','ec080f65-a83c-485e-acad-bd263df87245',92,'image',NULL,'book/29-people-os/580eb78f-db7a-4ccb-a5c8-573472d541f0-img21.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bb1ae29d-c764-4c1f-8242-a9147fce6252','29-people-os','e2474534-3dd0-44c4-89e2-b50d68f87e0d',3,'Ma Trận Khung Chỉ Số KPI Theo Từng Vị Trí Cốt Lõi In-Clinic','ma-tran-khung-chi-so-kpi-theo-tung-vi-tri-cot-loi-in-clinic',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78ba64bc-edb4-45ea-9f60-f37df90aa15e','bb1ae29d-c764-4c1f-8242-a9147fce6252',93,'text','Mọi vị trí trong đường ống vận hành của nha khoa đều phải được đóng gói bằng các chỉ số hiệu suất không thể làm giả. Dưới đây là khung KPI quy chuẩn áp dụng cho cấu trúc phòng khám tăng trưởng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc18fa53-85be-4030-a9b6-8dba27ec6e8e','29-people-os','e2474534-3dd0-44c4-89e2-b50d68f87e0d',3,'Chỉ Số Hoàn Thành Hiệu Suất Tổng Hợp (KPI_{\\text{index}})','chi-so-hoan-thanh-hieu-suat-tong-hop-kpitextindex',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86e3c9fb-2a2d-4e13-91f3-34f960b61176','dc18fa53-85be-4030-a9b6-8dba27ec6e8e',94,'text','Để xét duyệt khen thưởng hoặc đưa ra chế tài xử phạt cuối tháng một cách minh bạch, bộ phận nhân sự bắt buộc phải trích xuất chỉ số **Tỷ lệ hoàn thành KPI tổng hợp (****KPI_{\\text{index}}****)** của từng cá nhân trên CRM:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f2334e87-8a98-4027-8c92-7fa306748c98','dc18fa53-85be-4030-a9b6-8dba27ec6e8e',95,'text','KPI_{\\text{index}} (\\%) = \\left( \\frac{\\sum_{i=1}^{n} (\\text{Kết quả thực tế mục } i}{\\sum_{i=1}^{n} (\\text{Chỉ tiêu cam kết mục } i} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82d64081-0f2f-4406-935a-5304ee6a8b52','dc18fa53-85be-4030-a9b6-8dba27ec6e8e',96,'text','**Quy chế xử lý hiệu suất tiêu chuẩn trong Nha khoa:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0b817425-240a-46ac-8f7c-46482a42161b','dc18fa53-85be-4030-a9b6-8dba27ec6e8e',97,'text','- **KPI_{\\text{index}} \\ge 100\\%**** (Vùng Tăng tốc):** Kích hoạt cơ chế thưởng vượt ngưỡng, đưa nhân sự vào danh sách quy hoạch thăng tiến lên cấp quản lý.- **80\\% \\le KPI_{\\text{index}} < 99\\%**** (Vùng Đạt chuẩn):** Hưởng nguyên lương hiệu suất cơ bản, tiếp tục duy trì nhịp độ vận hành.- **KPI_{\\text{index}} < 70\\%**** (Vùng Báo động đỏ):** Hệ thống tự động kích hoạt quy trình PIP (Performance Improvement Plan - Kế hoạch cải thiện hiệu suất) kéo dài 14 ngày. Nếu kết quả tái sát hạch không cải thiện, phòng khám thực hiện sa thải nhân sự ngay trong chu kỳ để bảo vệ năng suất của bộ máy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2eab53a7-e201-40a1-871c-715405ce5a22','dc18fa53-85be-4030-a9b6-8dba27ec6e8e',98,'image',NULL,'book/29-people-os/fe994855-89ce-48a1-8092-d94702c6157c-img22.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b29fa6da-0264-4d3c-83fe-9682e1542a5d','dc18fa53-85be-4030-a9b6-8dba27ec6e8e',99,'text','**Mantra điều hành Performance Management:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e5a409d5-790f-455e-898d-8044d2eb63f3','dc18fa53-85be-4030-a9b6-8dba27ec6e8e',100,'text','*"Mọi hành vi không được đo lường sẽ không bao giờ được cải thiện. Đừng quản lý con người bằng cách đứng sau lưng giám sát hành động của họ, hãy quản lý bằng việc khóa chặt mục tiêu đầu ra định lượng. Con số sạch trên Dashboard chính là tiếng nói công bằng và danh giá nhất của một nhân sự tinh nhuệ."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('797cc2b7-4f8a-4472-8e1d-293d8d1dd6b3','29-people-os',NULL,2,'29.10 Compensation &amp; Incentive - Hệ Thống Đãi Ngộ Và Khen Thưởng Thông Minh','2910-compensation-amp-incentive-he-thong-ai-ngo-va-khen-thuong-thong-minh',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04d197cd-7179-4599-984d-7128d12ed583','797cc2b7-4f8a-4472-8e1d-293d8d1dd6b3',101,'text','Hệ thống đãi ngộ sai lầm là nguyên nhân cốt lõi khiến phòng khám nha khoa hoặc bị chảy máu chất xám (mất bác sĩ giỏi, phụ tá thạo việc), hoặc rơi vào bẫy gãy dòng tiền do quỹ lương phình to vô tội vạ. Lương thưởng trong hệ điều hành **People OS** không được nhìn nhận như một khoản "chi phí mất đi", mà là **khoản đầu tư chiến lược** để mua sắm hiệu suất và lòng trung thành của nhân sự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ffb15d75-3121-4532-a6f6-6d7a2e97f7ea','797cc2b7-4f8a-4472-8e1d-293d8d1dd6b3',102,'text','Để giải phóng động lực tự thân của đội ngũ, hệ thống đãi ngộ bắt buộc phải được thiết kế theo các nguyên tắc kinh tế học hành vi, gắn chặt quyền lợi túi tiền của nhân viên vào sự tăng trưởng của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('74c69019-61a6-4a0b-9758-1e17bebeeab0','29-people-os','797cc2b7-4f8a-4472-8e1d-293d8d1dd6b3',3,'Nguyên Tắc Thiết Kế Chiến Lược Lương Thưởng Nha Khoa','nguyen-tac-thiet-ke-chien-luoc-luong-thuong-nha-khoa',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b509dabe-cc31-4883-9293-a1a4a0cd4759','74c69019-61a6-4a0b-9758-1e17bebeeab0',103,'text','Một chính sách lương thưởng bền vững phải được xây dựng dựa trên 5 màng lọc cốt lõi sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bebcee65-325f-4786-803d-6524c2848f44','74c69019-61a6-4a0b-9758-1e17bebeeab0',104,'text','- **Gắn với Vai trò (Position):** Chi trả dựa trên độ phức tạp, trách nhiệm và mức độ rủi ro y khoa của vị trí đó trong bộ máy vận hành phòng khám.- **Gắn với Năng lực (Person):** Chi trả cho trình độ chuyên môn, bằng cấp lâm sàng, kỹ năng điểm chạm sảnh chờ và thâm niên thực chiến có giá trị của nhân sự.- **Gắn với Kết quả (Performance):** Chi trả sòng phẳng dựa trên các chỉ số KPI định lượng không thể làm giả được trích xuất từ CRM hằng tháng.- **Gắn với Mức độ đóng góp (Contribution):** Ghi nhận những nỗ lực vượt ngưỡng, các sáng kiến tối ưu hóa chi phí vật liệu hoặc nâng cấp trải nghiệm bệnh nhân.- **Khả năng giữ chân người giỏi (Retention):** Thiết kế lộ trình thăng tiến và quỹ thưởng tích lũy dài hạn nhằm biến nhân sự tinh nhuệ thành "đối tác chiến lược" gắn bó với phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f88c0a93-7af0-41b3-a870-34ac5b8455d9','29-people-os','797cc2b7-4f8a-4472-8e1d-293d8d1dd6b3',3,'Ma Trận Cấu Trúc Lương Thưởng 6 Tầng Toàn Diện','ma-tran-cau-truc-luong-thuong-6-tang-toan-dien',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb46b548-a159-452b-a957-8879ef0e36b3','f88c0a93-7af0-41b3-a870-34ac5b8455d9',105,'text','Hệ thống *People OS* đề xuất cấu trúc thu nhập tổng hợp chia làm 6 tầng chuyên biệt để áp dụng linh hoạt cho cả khối Lâm sàng lẫn khối Vận hành kinh doanh:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d2aad233-e918-4c76-aabb-ea4517a0ae5d','f88c0a93-7af0-41b3-a870-34ac5b8455d9',106,'image',NULL,'book/29-people-os/ad2c1044-0091-4add-b6ad-d903e98b2998-img23.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b1316e14-d807-4cfa-bbe3-a57742562ccf','29-people-os','797cc2b7-4f8a-4472-8e1d-293d8d1dd6b3',3,'Công Thức Thu Nhập Tổng Hợp (TC) Và Trần An Toàn Tài Chính','cong-thuc-thu-nhap-tong-hop-tc-va-tran-an-toan-tai-chinh',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f791ca2-001a-422a-a6b4-8d3250f6c943','b1316e14-d807-4cfa-bbe3-a57742562ccf',107,'text','Hằng tháng, kế toán trưởng tính toán tổng thu nhập của một nhân sự tinh nhuệ theo mô hình toán học dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ffaca29-b43b-4eed-80a6-07e8d25bfaa6','b1316e14-d807-4cfa-bbe3-a57742562ccf',108,'text','TC = B + KPI + R_{\\text{comm}} + Q_{\\text{bonus}} + Ref_{\\text{incentive}} + T_{\\text{bonus}}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4629a50d-ffcf-435a-aa22-3f0d8529e332','b1316e14-d807-4cfa-bbe3-a57742562ccf',109,'text','*Trong đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25ebf3d1-aaca-43c0-9ad8-be8001183cbf','b1316e14-d807-4cfa-bbe3-a57742562ccf',110,'text','- B: Lương cố định theo ngày công thực tế.- KPI: Tiền thưởng hiệu suất công việc đạt chuẩn.- R_{\\text{comm}}: Hoa hồng trích từ doanh thu thực thu phác đồ lâm sàng.- Q_{\\text{bonus}}: Tiền thưởng chất lượng dịch vụ và độ an toàn y khoa.- Ref_{\\text{incentive}}: Tiền thưởng khai thác nguồn khách hàng giới thiệu hữu cơ.- T_{\\text{bonus}}: Quỹ thưởng tích lũy khi toàn cơ sở cán mốc mục tiêu vĩ mô.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6b9b6630-fd27-4145-b20b-cd4a64b8370d','b1316e14-d807-4cfa-bbe3-a57742562ccf',111,'text','**Hạn mức siết trần an toàn tài chính từ Finance OS:** Để bảo vệ phòng khám khỏi nguy cơ mất thanh khoản, tổng quỹ lương và thưởng toàn bộ bộ máy (Khối sảnh + Khối lâm sàng) hằng tháng **tuyệt đối không được vượt quá ngưỡng 25% đến 30% doanh thu thuần thực thu** của tháng đó. Nếu chỉ số này tăng chạm ngưỡng 35%, chủ phòng khám phải lập tức siết chặt định biên nhân sự và cấu trúc lại tỷ lệ commission phần trăm ca của khối bác sĩ hợp tác để đưa biên lợi nhuận ròng về vùng xanh an toàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d706bcbc-e668-49c8-8a88-37d3f710e1b1','b1316e14-d807-4cfa-bbe3-a57742562ccf',112,'image',NULL,'book/29-people-os/d653b0af-f615-4000-969d-e00bb1b97a5d-img24.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4db0dbc-86de-4796-a8b3-f3be68b28880','b1316e14-d807-4cfa-bbe3-a57742562ccf',113,'text','**Mantra điều hành Đãi ngộ & Khen thưởng:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2544a2ad-03b8-4c7c-b691-4f5e43cf8971','b1316e14-d807-4cfa-bbe3-a57742562ccf',114,'text','*"Đừng bao giờ đòi hỏi lòng trung thành và hiệu suất đỉnh cao từ một đội ngũ bị bỏ đói về quyền lợi kinh tế. Ngược lại, đừng dung dưỡng thói quen hưởng lương an nhàn của những nhân sự không tạo ra giá trị. Hãy dùng cơ chế lương thưởng 6 tầng để biến phòng khám thành một sân chơi công bằng nơi người làm giỏi nhất luôn nhận được phần thưởng danh giá nhất."*',NULL,NULL,NULL,NULL,NULL);
