INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe78805c-8563-44b0-a517-6dd31736226a','ef749553-dafd-4b5d-9a72-9efc2b51a1fb',123,'text','*Trong đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('daa22a52-86cc-43c7-ac50-54fdf1e1db6b','ef749553-dafd-4b5d-9a72-9efc2b51a1fb',124,'text','- B: Lương cố định theo ngày công thực tế.- KPI: Tiền thưởng hiệu suất công việc đạt chuẩn.- R_{\\text{comm}}: Hoa hồng trích từ doanh thu thực thu phác đồ lâm sàng.- Q_{\\text{bonus}}: Tiền thưởng chất lượng dịch vụ và độ an toàn y khoa.- Ref_{\\text{incentive}}: Tiền thưởng khai thác nguồn khách hàng giới thiệu hữu cơ.- T_{\\text{bonus}}: Quỹ thưởng tích lũy khi toàn cơ sở cán mốc mục tiêu vĩ mô.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('31b513a9-4d01-45f5-83b7-17fd0fe00f39','ef749553-dafd-4b5d-9a72-9efc2b51a1fb',125,'text','**Hạn mức siết trần an toàn tài chính từ Finance OS:** Để bảo vệ phòng khám khỏi nguy cơ mất thanh khoản, tổng quỹ lương và thưởng toàn bộ bộ máy (Khối sảnh + Khối lâm sàng) hằng tháng **tuyệt đối không được vượt quá ngưỡng 25% đến 30% doanh thu thuần thực thu** của tháng đó. Nếu chỉ số này tăng chạm ngưỡng 35%, chủ phòng khám phải lập tức siết chặt định biên nhân sự và cấu trúc lại tỷ lệ commission phần trăm ca của khối bác sĩ hợp tác để đưa biên lợi nhuận ròng về vùng xanh an toàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e060b0db-924e-4a08-9f5f-4b29d52e7ded','ef749553-dafd-4b5d-9a72-9efc2b51a1fb',126,'image',NULL,'book/29-people-os/5f0b7be8-f648-4536-a052-df0eb068ecfb-img26.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37b636c9-755c-4997-8acd-0b48907f85d9','ef749553-dafd-4b5d-9a72-9efc2b51a1fb',127,'text','**Mantra điều hành Đãi ngộ & Khen thưởng:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4cf0d3e4-4aa9-4947-b48f-d4d608f65032','ef749553-dafd-4b5d-9a72-9efc2b51a1fb',128,'text','*"Đừng bao giờ đòi hỏi lòng trung thành và hiệu suất đỉnh cao từ một đội ngũ bị bỏ đói về quyền lợi kinh tế. Ngược lại, đừng dung dưỡng thói quen hưởng lương an nhàn của những nhân sự không tạo ra giá trị. Hãy dùng cơ chế lương thưởng 6 tầng để biến phòng khám thành một sân chơi công bằng nơi người làm giỏi nhất luôn nhận được phần thưởng danh giá nhất."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5241fd6f-c183-4f81-a7b2-9c5e679ccf2c','29-people-os',NULL,2,'29.12 Tổng Kết People OS - Bánh Đà Giải Phóng Và Nhân Bản Năng Lực Tổ Chức','2912-tong-ket-people-os-banh-a-giai-phong-va-nhan-ban-nang-luc-to-chuc',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('edbf81c2-89d3-4524-8124-d3f910f45b73','5241fd6f-c183-4f81-a7b2-9c5e679ccf2c',129,'text','Khép lại phân hệ **People OS Playbook**, hạ tầng quản trị con người của một nha khoa tăng trưởng đã được đóng gói trọn vẹn thành một hệ điều hành logic và có tính kế thừa cao. Nếu **Finance OS** là hệ thống phanh và bộ giáp bảo vệ dòng tiền, thì **People OS** chính là **khối động cơ vĩnh cửu** chuyển hóa các mục tiêu tài chính trên giấy thành thực tế đầu ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d21f4d54-9bcf-4fb2-9dee-39db0c31ee8a','5241fd6f-c183-4f81-a7b2-9c5e679ccf2c',130,'text','Suy cho cùng, thiết bị công nghệ cao không tự vận hành, phác đồ điều trị không tự đóng gói, và bệnh nhân không tự nhiên có được trải nghiệm chạm. Tất cả phụ thuộc vào năng lực thực thi của đội ngũ trực sàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f515cd8-9360-44cb-8907-b2b96a742c64','5241fd6f-c183-4f81-a7b2-9c5e679ccf2c',131,'image',NULL,'book/29-people-os/cdcef99c-7c85-44ca-8a1b-bb7fe4c9092e-img27.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d25903c2-08cf-48c6-856b-2edaaddb7203','29-people-os','5241fd6f-c183-4f81-a7b2-9c5e679ccf2c',3,'Ba Cột Mốc Định Lượng Siết Chặt Sức Khỏe Tổ Chức','ba-cot-moc-inh-luong-siet-chat-suc-khoe-to-chuc',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3dca9c1a-1696-4e48-9726-735f534a43a2','d25903c2-08cf-48c6-856b-2edaaddb7203',132,'text','Để đảm bảo bộ máy nhân sự luôn tinh nhuệ, tự chủ và không biến quỹ lương thành gánh nặng ngốn sạch lợi nhuận ròng, chủ phòng khám bắt buộc phải giám sát bộ ba mỏ neo toán học tối cao này hằng tháng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d6eab4d-d160-44c9-a04d-c8ccf34bf75f','d25903c2-08cf-48c6-856b-2edaaddb7203',133,'image',NULL,'book/29-people-os/ecdaf538-1df0-4e4e-901a-e13e229c4755-img28.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8883d9b4-1a5c-4705-876d-1c295929b3e4','d25903c2-08cf-48c6-856b-2edaaddb7203',134,'text','**Chốt chặn 1 - Hiệu suất sinh lời tài nguyên người (****HCROI_{\\text{clinical}}****):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d928916-d676-4e6d-8ce6-e5b92b75d289','d25903c2-08cf-48c6-856b-2edaaddb7203',135,'text','- HCROI_{\\text{clinical}} \\ge 3.0
- Cứ 1 đồng chi ra cho quỹ lương và thưởng của nhân sự, đội ngũ đó phải tạo ra tối thiểu 3 đồng doanh thu thuần sau khi trừ giá vốn vật liệu lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c47906e0-56e3-404d-aea4-7dfd4a683583','d25903c2-08cf-48c6-856b-2edaaddb7203',136,'text','**Chốt chặn 2 - Độ tự do của người điều hành (****MLI****):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fca5f475-245d-4e50-a15f-04cb62b95ef6','d25903c2-08cf-48c6-856b-2edaaddb7203',137,'text','- MLI \\ge 4.0
- Thời gian chủ phòng khám dành cho việc chiến lược vĩ mô và chuyên môn sâu phải gấp tối thiểu 4 lần thời gian phải lao vào xử lý sự cố vận hành vụn vặt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fcb7dfe4-b2ab-45ab-942b-9cfa13f8f017','d25903c2-08cf-48c6-856b-2edaaddb7203',138,'text','**Chốt chặn 3 - Kỷ luật đồng bộ bộ máy (****MCR****):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0a6f10b-f6fd-46c3-8cba-14eaa4a384e2','d25903c2-08cf-48c6-856b-2edaaddb7203',139,'text','- MCR \\ge 95\\%
- Đảm bảo các nhịp đập sinh học (Daily Huddle, Giao ban tuần, Họp chiến lược) được diễn ra nghiêm túc, đúng giờ để triệt tiêu các "ốc đảo thông tin".',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('87db9e21-603e-446a-9a31-f7f1fa974065','29-people-os','5241fd6f-c183-4f81-a7b2-9c5e679ccf2c',3,'Sự Chuyển Dịch Vị Thế Của Chủ Phòng Khám Nha Khoa','su-chuyen-dich-vi-the-cua-chu-phong-kham-nha-khoa',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34f125fb-0c25-4fbd-ace0-ab5483aad084','87db9e21-603e-446a-9a31-f7f1fa974065',140,'text','Khi 8 cấu phần của People OS (từ khâu Tuyển dụng, Hội nhập, Đào tạo cho đến Quản trị hiệu suất và Đãi ngộ) được ráp nối khít khao, người chủ sẽ chính thức bước ra khỏi vòng xoáy "khổ chủ":',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cff724de-ed43-42a5-9fb6-3891806f6876','87db9e21-603e-446a-9a31-f7f1fa974065',141,'image',NULL,'book/29-people-os/06617e33-84b1-4ea4-8cb0-0103ce74d4a3-img29.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a4ddc80-85fd-451c-b328-9778b21670b9','87db9e21-603e-446a-9a31-f7f1fa974065',142,'text','Phòng khám sẽ không còn bị tổn thương hay đứng bóng dòng tiền khi một "nhân sự ngôi sao" rời đi. Tiêu chuẩn dịch vụ và chất lượng y khoa được bảo chứng đồng đều 100% trên mọi lượt khách, tạo nền tảng vững chắc để sẵn sàng nhân bản sang các cơ sở tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d975fed-eb1e-4e09-acd1-5feb24cab915','87db9e21-603e-446a-9a31-f7f1fa974065',143,'text','**Mantra tối cao khóa phân hệ People OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e742e864-6082-4140-a409-e9e19d14d12c','87db9e21-603e-446a-9a31-f7f1fa974065',144,'text','*"Tài sản lớn nhất của một phòng khám nha khoa không phải là những chiếc ghế nha đắt tiền hay những máy chụp phim công nghệ cao, tài sản lớn nhất là một hệ thống quản trị con người khoa học giúp biến những nhân sự bình thường thành một đội ngũ thực thi phi thường. Hãy điều hành con người bằng luật chơi sòng phẳng và kỷ luật thép, để giải phóng chính mình và nâng tầm doanh nghiệp."*',NULL,NULL,NULL,NULL,NULL);
